# Simple Monolithic Deployment
# Architecture:
#   [Load Balancer] → [App Instance 1] \
#                    → [App Instance 2]  → [Database]
#                    → [App Instance 3] /
#
# nginx.conf - Load balance across monolith instances
upstream monolith_cluster {
    least_conn;
    server 10.0.1.10:3000;
    server 10.0.1.11:3000;
    server 10.0.1.12:3000;
}

server {
    listen 443 ssl http2;
    server_name app.example.com;

    location / {
        proxy_pass http://monolith_cluster;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    # Session affinity (sticky sessions) for in-memory state
    # Alternatively: move sessions to Redis to avoid affinity requirement
}
